#include <stdio.h>
#include <stdlib.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int B, K; long long M, N; scanf("%d %lld %lld %d", &B, &M, &N, &K);
        double *C = (double*)malloc((B+2)*sizeof(double));
        for(int i=1;i<=B;i++) C[i] = (double)M;
        for(int i=1;i<B;i++){
            double total = (double)(M+N + (i-1));
            double move = i * C[i] / total;
            C[i] -= move;
            C[i+1] += move;
        }
        printf("%.10f\n", C[K]);
        free(C);
    }
    return 0;
}

