import java.io.*;
import java.util.*;
public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int B = fs.nextInt();
            long M = fs.nextLong();
            long N = fs.nextLong();
            int K = fs.nextInt();
            double[] C = new double[B + 2];
            Arrays.fill(C, M);
            for (int i = 1; i < B; i++) {
                double total = (double)(M + N + (i - 1));
                double move = i * C[i] / total;
                C[i] -= move;
                C[i + 1] += move;
            }
            sb.append(String.format(java.util.Locale.US, "%.10f\n", C[K]));
        }
        System.out.print(sb.toString());
    }
    static class FastScanner {
        private final BufferedInputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream is) { in = new BufferedInputStream(is); }
        private int readByte() throws IOException {
            if (ptr >= len) { len = in.read(buffer); ptr = 0; if (len <= 0) return -1; }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { int c, sign = 1, val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign; }
        long nextLong() throws IOException { int c, sign = 1; long val = 0; do { c = readByte(); } while (c <= ' ');
            if (c == '-') { sign = -1; c = readByte(); }
            while (c > ' ') { val = val * 10 + c - '0'; c = readByte(); }
            return val * sign; }
    }
}

